mapper.select:
select product_id, product_name, order_id, order_time, total_amount, status, pay_url
from pay_order
where user_id = #{userId}
  and product_id = #{productId}
order by id desc
limit 1

mapper.update:
update pay_order set status = 'MARKET', update_time = now()
where order_id = #{orderId}
  and status = 'DEAL_DONE'

mapper.select:
select id, user_id, product_id, product_name, order_id, order_time, total_amount, status, pay_url, market_type, market_deduction_amount, pay_amount
from pay_order
where order_id = #{orderId}

select id, user_id, product_id, product_name, order_id, order_time, total_amount, status, pay_url, pay_time,
       market_type, market_deduction_amount, pay_amount, create_time, update_time
from pay_order
where user_id = #{userId}

    and id < #{lastId}

order by id desc
limit #{pageSize}

mapper.update:
update pay_order set status = 'REFUNDED', update_time = now()
where order_id = #{orderId}
  and user_id = #{userId}
  and status in ('PAY_WAIT', 'PAY_SUCCESS', 'MARKET', 'DEAL_DONE')

update pay_order set status = 'REFUNDING', update_time = now()
where order_id = #{orderId}
  and user_id = #{userId}
  and status in ('PAY_WAIT', 'PAY_SUCCESS', 'MARKET', 'DEAL_DONE')

update pay_order set status = 'REFUNDED', update_time = now()
where order_id = #{orderId}
  and status = 'REFUNDING'
